import React, { useState } from 'react';
import confetti from 'canvas-confetti';

export default function App() {
  const [count, setCount] = useState(0);

  const handleConfetti = () => {
    setCount(c => c + 1);
    confetti({
      particleCount: 100,
      spread: 70,
      origin: { y: 0.6 }
    });
  };

  return (
    <div style={{
      fontFamily: 'system-ui, sans-serif',
      padding: '2rem',
      textAlign: 'center',
      background: 'linear-gradient(135deg, #0f172a, #1e1b4b)',
      color: '#f8fafc',
      minHeight: '100vh',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      alignItems: 'center'
    }}>
      <h1 style={{ fontSize: '3rem', margin: '0 0 1rem 0', background: 'linear-gradient(to right, #38bdf8, #818cf8)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
        Live Sandbox App
      </h1>
      <p style={{ color: '#94a3b8', fontSize: '1.2rem', marginBottom: '2rem' }}>
        Edit <code>src/App.jsx</code> and watch the updates happen in near real-time!
      </p>

      <div style={{ display: 'flex', gap: '1rem', justifyContent: 'center' }}>
        <button 
          onClick={() => setCount(c => c + 1)}
          style={{
            background: '#2563eb',
            color: 'white',
            border: 'none',
            padding: '0.75rem 1.5rem',
            fontSize: '1rem',
            fontWeight: '600',
            borderRadius: '0.5rem',
            cursor: 'pointer',
            boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
            transition: 'background 0.2s'
          }}
        >
          Count: {count}
        </button>

        <button 
          onClick={handleConfetti}
          style={{
            background: 'linear-gradient(135deg, #ec4899, #8b5cf6)',
            color: 'white',
            border: 'none',
            padding: '0.75rem 1.5rem',
            fontSize: '1rem',
            fontWeight: '600',
            borderRadius: '0.5rem',
            cursor: 'pointer',
            boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
            transition: 'opacity 0.2s'
          }}
        >
          Pop Confetti! 🎉
        </button>
      </div>

      <div style={{ marginTop: '3rem', color: '#64748b', fontSize: '0.9rem' }}>
        Installed packages used: <code>canvas-confetti</code>
      </div>
    </div>
  );
}

